UPDATE challenge_application ca JOIN challenge c ON ca.challenge_id = c.id
ca.status = #{status}, c.participant_count = CASE WHEN #{status} = 1 THEN c.participant_count + 1 ELSE c.participant_count END
WHERE ca.id = #{id}

UPDATE challenge_application
SET
    status = #{status},
    remark = #{remark}
WHERE id = #{id}
